+/// Sanitize agent name for use in filesystem paths.
+///
+/// Replaces non-alphanumeric characters with underscore.
+#[must_use]
+pub fn sanitize_agent_name(name: &str) -> String {
+    name.chars()
+        .map(|c| if c.is_ascii_alphanumeric() { c } else { '_' })
+        .collect()
+}
