+/// Inbox row that includes project context for global inbox view.
+#[derive(Debug, Clone)]
+pub struct GlobalInboxRow {
+    pub message: MessageRow,
+    pub kind: String,
+    pub sender_name: String,
+    pub ack_ts: Option<i64>,
+    pub project_id: i64,
+    pub project_slug: String,
