+
+        match &fts_result {
+            Outcome::Err(_) => {
+                tracing::warn!(
+                    "Global FTS query failed for '{}', attempting LIKE fallback",
+                    query
+                );
+                let terms = extract_like_terms(query, 5);
+                if terms.is_empty() {
+                    Outcome::Ok(Vec::new())
+                } else {
+                    run_like_fallback_global(cx, &tracked, &terms, limit_i64).await
