+        if selected {
+            line.apply_base_style(cursor_style);
+        }
+
+        ftui::widgets::paragraph::Paragraph::new(ftui::text::Text::from_line(line))
+            .render(area, frame);
+    }
+
+    fn height(&self) -> u16 {
